1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function calculateItemPremium(item: any): number {
14	  const base = BASE_PREMIUMS[item.type];
15	  let premium = base;
16	  if (item.cursed) {
17	    premium += base * 0.5;
18	  }
19	  if (item.enchantment >= 5) {
20	    premium += base * 0.3;
21	  }
22	  return premium;
23	}
24	
25	export function claimOffice(input: any): unknown {
26	  const items = input.steps[0].items;
27	  let itemsTotal = 0;
28	  let policyBase = 0;
29	
30	  const typeCounts: Record<string, number> = {};
31	  for (const item of items) {
32	    itemsTotal += calculateItemPremium(item);
33	    policyBase += BASE_PREMIUMS[item.type];
34	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
35	  }
36	
37	  for (const type in typeCounts) {
38	    if (typeCounts[type] === 3) {
39	      itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
40	    }
41	  }
42	
43	  let policyModifier = 0;
44	  if (input.customer.yearsWithMHPCO >= 2) {
45	    policyModifier -= policyBase * 0.2;
46	  }
47	  policyModifier += policyBase * 0.1;
48	
49	  const premium = Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
50	  return { results: [{ premium }] };
51	}
